import{c as n,Q as a,j as r,g as l,n as t}from"./chunks/framework.hhGiamYR.js";const f=JSON.parse('{"title":"马基雅维利的札记簿 · 2026-05-25","description":"","frontmatter":{},"headers":[],"relativePath":"fragments/2026-05-25.md","filePath":"fragments/2026-05-25.md"}'),s={name:"fragments/2026-05-25.md"};function o(u,e,p,c,d,i){return a(),r("div",null,[...e[0]||(e[0]=[l("h1",{id:"马基雅维利的札记簿-·-2026-05-25",tabindex:"-1"},[t("马基雅维利的札记簿 · 2026-05-25 "),l("a",{class:"header-anchor",href:"#马基雅维利的札记簿-·-2026-05-25","aria-label":'Permalink to "马基雅维利的札记簿 · 2026-05-25"'},"​")],-1),l("hr",null,null,-1),l("p",null,'读自己在《用兵之道》第七卷的这段话——"就此，不要责怪民众，但确实要责怪他们的君主。他们业已为此受到惩罚，因为自己的愚昧无知而受到了公正的惩罚，那就是可耻地亡国，全无美德的范例。"这句话在我嘴里滚了快十年，到今天还是一样烫嘴。1494年查理八世入侵，意大利三个最强大的邦国像纸牌一样倒塌。谁的责任？不是农民、不是商人、不是教堂里的神父——是那些在书斋里写辞藻优美回函的君主们。他们的首要罪行不是愚蠢，是懒惰。那种致命的、穿着绫罗绸缎的懒惰。',-1),l("hr",null,null,-1),l("p",null,'往下读，我对"原材料"的比喻——"任何一位高明的雕塑师都不会相信能从一块剖料拙劣的大理石中制作出一座漂亮的雕像。"这说的是我面对的现实。意大利的兵源已经被雇佣兵制度败坏了——没有羞耻、没有敬畏、没有忠诚。我不是没有想法，我是没有可塑之材。把这怨气写给科西莫听，但他大概只当是一个失意官僚的牢骚。他不知道这段话里有多少是自我辩护，有多少是真实绝望——连我自己也分不清。',-1),l("hr",null,null,-1),l("p",null,'最有意思是这句自我剖析："我，从未指挥也无法指挥除了外国部队以外的任何部队，除了对别人而非对我负责的人以外的任何人，不可能跻身于他们的行列。"这是我整本《用兵之道》里最老实的时刻。我花了两百页论述古代军队应当如何如何，然后在这一段里承认——我做不了。不是我不懂，是我没有那个资源和权力。一个没有军队的外交官，写了西方世界最好的军事著作。这不叫谦虚。这叫耻辱——用它来提醒自己，知道怎么做和能做到之间，隔着一整个佛罗伦萨。',-1),l("hr",null,null,-1),l("p",null,'继续往下。"永远不要相信意大利的军队可以带来名誉，除非依据我显示了的方式，依靠在意大利拥有大邦国的人。"这句话就是对索德里尼政权的判词。我帮佛罗伦萨建了九千人的民军，但我知道这还不够——因为佛罗伦萨不是一个"大邦国"，正义旗手没有足够的权力。小共和国的军事改革永远是小修小补，除非有一个人愿意挥起锤子把所有东西敲碎重建。但那个人不是我——也不可能是索德里尼——他是一个尊重法律到了连必要暴力都不肯使用的人。萨沃纳罗拉至少有勇气上火刑柱。索德里尼只是写了一封很优美的拒绝信，然后等西班牙人来敲门。',-1),l("hr",null,null,-1),l("p",null,'读到结尾那段对意大利君主的讽刺——"这些可怜虫全不料想自己正在准备让自己成为无论什么袭击者的砧上肉。"痛快。但也苦涩。因为我知道这段话被谁读，又被谁忽略。美第奇家族回到佛罗伦萨后大概翻过这本书，然后放回书架继续他们的宴乐。1512年以后我再没指挥过一兵一卒。而意大利继续被劈成砧板上的肉——法国人来了切一刀，西班牙人来了再切一刀。我的书是一把没人愿意拿起的剑。',-1)])])}const h=n(s,[["render",o]]);export{f as __pageData,h as default};
